function slug(t: string): string {
  return t.toLowerCase().replace(/[　\s]+/g, "-").replace(/[！!？?。、・「」『』（）()【】\[\]＆&\'"＋＝]+/g, "").replace(/-+/g, "-").replace(/^-|-$/g, "");
}

